server
{
listen 80;
server_name p2p.witque.cn;

location /{
proxy_pass http://127.0.0.1:4000;
proxy_redirect off;
proxy_set_header X-Real-IP $remote_addr;
proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
proxy_set_header Host $http_host;
proxy_set_header X-NginX-Proxy true;
}

location /api{
proxy_pass http://127.0.0.1:7500/api;
}

location /static {
return 301 $request_uri/frp/;
}

location /frp/{
proxy_pass http://127.0.0.1:7500/static/;
}

}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const target = `http://origin.yourdomain.com:端口${url.pathname}${url.search}`;

    const newHeaders = new Headers(request.headers);
    newHeaders.set('Host', 'origin.yourdomain.com:端口');

    return fetch(target, {
      method: request.method,
      headers: newHeaders,
      body: ['GET', 'HEAD'].includes(request.method) ? null : request.body,
      redirect: 'follow',
    });
  }
}
